import React, { useState, useRef, useEffect } from 'react';
import { useHistory } from "react-router-dom";

import {Table, Form} from 'react-bootstrap';
import arraySort from 'array-sort'
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
import { faAngleDoubleLeft, faCaretDown, faCaretUp } from '@fortawesome/free-solid-svg-icons'
import ReactTooltip from 'react-tooltip' 

import PaginationList from './PaginationList'

import { useDispatch, useSelector } from 'react-redux'

import './SelectMenu.css'

// Retorna um array com os filtros aplicados
const searchBy = (searchString, listaOcupacoesFiltrado, itemList, field, Refs) => {

    itemList = listaOcupacoesFiltrado && listaOcupacoesFiltrado.length > 0 ? listaOcupacoesFiltrado:itemList

    searchString = searchString.trim()
    let newList = []

    if(Refs.family.current.value.trim() === '' && Refs.ocupation.current.value.trim() === '')
        return false

    itemList.filter((item) => {

        if(item[field].toLowerCase().includes(searchString.toLowerCase())){

            newList.push(item)

            return true
        }

        return false
    })

    return newList
}

const toggleSortDirection = (sortDirection) => {
    if(sortDirection === 'asc')
        return 'desc'
    
    return 'asc'
}

const SelectOcupation = ({listaOcupacoes, ocupacoes, pagesQty, setPagesQty, pagesQtyAdded, setPagesQtyAdded, itemsPerPage}) => {

    // Variáveis de configuração de exibição
    const fieldFamilia = 'NM_TITULO_FAMILIA'
    const fieldOcupacao = 'NM_OCUPACAO'

    // Criando a referência para os campos de busca
    let RefsAll = {}
    RefsAll.family = useRef('')
    RefsAll.ocupation = useRef('')

    let RefsAdded = {}
    RefsAdded.family = useRef('')
    RefsAdded.ocupation = useRef('')

    // State da página atual
    const [actualPage, setActualPage] = useState(1)
    const [actualPageAdded, setActualPageAdded] = useState(1)
    const [itemList, setItemList] = useState(listaOcupacoes)
    const [addedList, setAddedList] = useState(listaOcupacoes)

    // States do sort
    const [sortDirectionLeftFamily, setSortDirectionLeftFamily] = useState(false)
    const [sortDirectionLeftOcupation, setSortDirectionLeftOcupation] = useState(false)
    const [sortDirectionRightFamily, setSortDirectionRightFamily] = useState(false)
    const [sortDirectionRightOcupation, setSortDirectionRightOcupation] = useState(false)

    // Valores do Redux
    const listaOcupacoesFiltrado = useSelector(state => state.listaOcupacoesFiltrado)
    const ocupacoesFiltrado = useSelector(state => state.ocupacoesFiltrado)

    // Effect dos items
    useEffect(() => {
        if(listaOcupacoesFiltrado){
            setPagesQty( Math.ceil(listaOcupacoesFiltrado.length / itemsPerPage))
            setItemList(listaOcupacoesFiltrado)

        }
        else{
            setItemList(listaOcupacoes)
            setPagesQty( Math.ceil(listaOcupacoes.length / itemsPerPage))
        }
        
        setActualPage(1)

    }, [listaOcupacoesFiltrado, listaOcupacoes])

    // Effect dos items
    useEffect(() => {
        if(ocupacoesFiltrado){
            setPagesQtyAdded( Math.ceil(ocupacoesFiltrado.length / itemsPerPage))
            setAddedList(ocupacoesFiltrado)

        }
        else{
            setAddedList(ocupacoes)
            setPagesQtyAdded( Math.ceil(ocupacoes.length / itemsPerPage))
        }
        
        setActualPageAdded(1)

    }, [ocupacoesFiltrado, ocupacoes])
    


    const history = useHistory()

    // Setando o Redux
    const dispach = useDispatch()

    return (
        <div className='select-list-container'>
            <div className='select-left'>
                <Table  responsive>
                    <thead>
                        <tr className='menuItemColumn'>
                            <th className='title'>Lista de Ocupações</th>
                        </tr>
                    </thead>
                    <thead>
                        <tr className='menuItemColumn'>
                            <th className='familiaOcupacional' onClick={() => {

                                const direction = toggleSortDirection(sortDirectionLeftFamily)

                                setItemList(arraySort(itemList, fieldFamilia, {reverse: direction === 'asc' ? false:true}))

                                setSortDirectionLeftOcupation(false)
                                setSortDirectionLeftFamily(direction)
                            }}>
                                Família Ocupacional
                                {sortDirectionLeftFamily && sortDirectionLeftFamily === 'asc' ? <FontAwesomeIcon className='caret' icon={faCaretUp}/>:''}
                                {sortDirectionLeftFamily && sortDirectionLeftFamily === 'desc' ? <FontAwesomeIcon className='caret' icon={faCaretDown}/>:''}
                            </th>
                            <th onClick={() => {
                                const direction = toggleSortDirection(sortDirectionLeftOcupation)
                                
                                setItemList(arraySort(itemList, fieldOcupacao, {reverse: direction === 'asc' ? false:true}))

                                setSortDirectionLeftFamily(false)
                                setSortDirectionLeftOcupation(direction)
                            }}>
                                Ocupação
                                {sortDirectionLeftOcupation && sortDirectionLeftOcupation === 'asc' ? <FontAwesomeIcon className='caret' icon={faCaretUp}/>:''}
                                {sortDirectionLeftOcupation && sortDirectionLeftOcupation === 'desc' ? <FontAwesomeIcon className='caret' icon={faCaretDown}/>:''}
                            </th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr className='menuItemColumn'>
                            <td className='familiaOcupacional'>
                                <Form.Control ref={RefsAll.family} type="text" placeholder="Família" onChange={(e) => { 
                                    let familyFiltered

                                    if(e.currentTarget.value === '' && RefsAll.ocupation.current.value !== ''){
                                        familyFiltered = searchBy(RefsAll.ocupation.current.value, listaOcupacoesFiltrado, listaOcupacoes, fieldOcupacao, RefsAll)
                                    }else{
                                        familyFiltered = searchBy(e.currentTarget.value, listaOcupacoesFiltrado, itemList, fieldFamilia, RefsAll)
                                    }
                                    
                                    dispach({ type: 'FILTER_OCUPATION', filtered: familyFiltered }) 

                                }}/>
                            </td>
                            <td >
                                <Form.Control ref={RefsAll.ocupation} type="text" placeholder="Ocupação" onChange={(e) => { 
                                    
                                    let familyFiltered

                                    if(e.currentTarget.value === '' && RefsAll.family.current.value !== ''){
                                        familyFiltered = searchBy(RefsAll.family.current.value, listaOcupacoesFiltrado, listaOcupacoes, fieldFamilia, RefsAll)
                                    }else{
                                        familyFiltered = searchBy(e.currentTarget.value, listaOcupacoesFiltrado, itemList, fieldOcupacao, RefsAll)
                                    }
                                    
                                    dispach({ type: 'FILTER_OCUPATION', filtered: familyFiltered }) 

                                    
                                }}/>
                            </td>
                        </tr>
                        {
                            itemList.slice( ((itemsPerPage*actualPage)-itemsPerPage), ((itemsPerPage*actualPage)) ).map((item) => {

                                return(
                                    
                                    <tr className='menuItemColumn' onClick={(e) => {
                                        
                                        dispach({ type: 'ADD_OCUPATION', item: item })
                                        RefsAdded.family.current.value = ''
                                        RefsAdded.ocupation.current.value = ''

                                    }}>
                                        <td className='familiaOcupacional'>
                                            <div className='select'>Adicionar</div>

                                                <h5>
                                                    {item[fieldFamilia]}
                                                </h5>
                                        </td>

                                        <td >
                                            <div className='select'></div>
                                            <h5>
                                                {item[fieldOcupacao]}
                                            </h5>
                                            
                                        </td>
                                    </tr>
                                    
                                )
                                
                            })
                        }
                    </tbody>
                </Table>
                <div className='pagination'>
                    <PaginationList
                        actualPage={actualPage}
                        setActualPage={setActualPage}
                        pagesQty={pagesQty}
                    />
                </div>
                {/* <button onClick={() => {
                    console.log({ocupacoes, listaOcupacoes})
                }}>State</button> */}
            </div>
            <div className='select-middle' onClick={() => {
                if(ocupacoes && ocupacoes.length > 0){
                    ocupacoes.forEach((item) => {
                        dispach({ type: 'REMOVE_OCUPATION', item: item }) 
                    })

                    RefsAll.family.current.value = ''
                    RefsAll.ocupation.current.value = ''
                }
                
                
            }}>
                <p data-tip="Remover todas as ocupações"><FontAwesomeIcon className='disselect' icon={faAngleDoubleLeft} /></p>
                <ReactTooltip place="left" type="info" effect="float"/>
            </div>
            
            <div className='select-right'>
                <Table  responsive>
                    <thead>
                        <tr className='menuItemColumn'>
                            <th className='title'>Ocupações Selecionadas</th>
                        </tr>
                    </thead>
                    <thead>
                        <tr className='menuItemColumn'>
                            <th className='familiaOcupacional' onClick={() => {

                                const direction = toggleSortDirection(sortDirectionRightFamily)

                                setAddedList(arraySort(addedList, fieldFamilia, {reverse: direction === 'asc' ? false:true}))

                                setSortDirectionRightOcupation(false)
                                setSortDirectionRightFamily(direction)
                            }}>
                                Família Ocupacional
                                {sortDirectionRightFamily && sortDirectionRightFamily === 'asc' ? <FontAwesomeIcon className='caret' icon={faCaretUp}/>:''}
                                {sortDirectionRightFamily && sortDirectionRightFamily === 'desc' ? <FontAwesomeIcon className='caret' icon={faCaretDown}/>:''}
                            </th>
                            <th onClick={() => {
                                const direction = toggleSortDirection(sortDirectionRightOcupation)
                                
                                setAddedList(arraySort(addedList, fieldOcupacao, {reverse: direction === 'asc' ? false:true}))

                                setSortDirectionRightFamily(false)
                                setSortDirectionRightOcupation(direction)
                            }}>
                                Ocupação
                                {sortDirectionRightOcupation && sortDirectionRightOcupation === 'asc' ? <FontAwesomeIcon className='caret' icon={faCaretUp}/>:''}
                                {sortDirectionRightOcupation && sortDirectionRightOcupation === 'desc' ? <FontAwesomeIcon className='caret' icon={faCaretDown}/>:''}
                            </th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr className='menuItemColumn'>
                            <td className='familiaOcupacional'>
                                <Form.Control ref={RefsAdded.family} type="text" placeholder="Família" onChange={(e) => { 
                                    let familyFiltered

                                    if(e.currentTarget.value === '' && RefsAdded.ocupation.current.value !== ''){
                                        familyFiltered = searchBy(RefsAdded.ocupation.current.value, ocupacoesFiltrado, ocupacoes, fieldOcupacao, RefsAdded)
                                    }else{
                                        familyFiltered = searchBy(e.currentTarget.value, ocupacoesFiltrado, addedList, fieldFamilia, RefsAdded)
                                    }

                                    dispach({ type: 'FILTER_OCUPATION_ADDED', filtered: familyFiltered }) 

                                    
                                }}/>
                            </td>
                            <td >
                                <Form.Control ref={RefsAdded.ocupation} type="text" placeholder="Ocupação" onChange={(e) => { 
                                    
                                    let familyFiltered

                                    if(e.currentTarget.value === '' && RefsAdded.family.current.value !== ''){
                                        familyFiltered = searchBy(RefsAdded.family.current.value, ocupacoesFiltrado, ocupacoes, fieldFamilia, RefsAdded)
                                    }else{
                                        familyFiltered = searchBy(e.currentTarget.value, ocupacoesFiltrado, addedList, fieldOcupacao, RefsAdded)
                                    }

                                    dispach({ type: 'FILTER_OCUPATION_ADDED', filtered: familyFiltered }) 

                                }}/>
                            </td>
                        </tr>
                        {
                            addedList.slice( ((itemsPerPage*actualPage)-itemsPerPage), ((itemsPerPage*actualPage)) ).map((item) => {

                                return(
                                    
                                    <tr className='menuItemColumn' onClick={(e) => {
                                        dispach({ type: 'REMOVE_OCUPATION', item: item }) 
                                        RefsAll.family.current.value = ''
                                        RefsAll.ocupation.current.value = ''

                                    }}>
                                        <td className='familiaOcupacional'>
                                            <div className='unselect'>Remover</div>

                                                <h5>
                                                    {item[fieldFamilia]}
                                                </h5>
                                        </td>

                                        <td >
                                            <div className='select'></div>
                                            <h5>
                                                {item[fieldOcupacao]}
                                            </h5>
                                            
                                        </td>
                                    </tr>
                                    
                                )
                                
                            })
                        }
                    </tbody>
                </Table>
                <div className='pagination'>
                    <PaginationList
                        actualPage={actualPageAdded}
                        setActualPage={setActualPageAdded}
                        pagesQty={pagesQtyAdded}
                    />
                </div>
                
            </div>
        </div>
        
        

        

    )
}


export default SelectOcupation;