import { Pagination } from "react-bootstrap"

import React from 'react'

import './PaginationList.css'


const PaginationList = ({actualPage, setActualPage, pagesQty}) => {
    // Adiciona os números da paginação
    let items = []
    const paginationLast = actualPage <= 2 ? 5:actualPage+2
    const paginationFirst = actualPage <= 2 ? 1:(actualPage+2 > pagesQty ? actualPage-(4-(pagesQty-actualPage)):actualPage-2)

    for (let number = paginationFirst; number <= pagesQty && number <= paginationLast; number++) {

        items.push(
            <Pagination.Item active={actualPage === number} key={number} onClick={() => {
                setActualPage(number)
            }}>
                {number}
            </Pagination.Item>
        );
    }

    return (
        <Pagination>
                <Pagination.First onClick={() => {
                    setActualPage(1)
                }}/>
                <Pagination.Prev onClick={() => {
                    if(actualPage-1 >= 1)
                        setActualPage(actualPage-1)
                }}/>
                    {items}
                <Pagination.Next onClick={() => {
                    if(actualPage+1 <= pagesQty)
                        setActualPage(actualPage+1)
                }}/>
                <Pagination.Last onClick={() => {
                    console.log(pagesQty)
                    setActualPage(pagesQty)
                }}/>
            </Pagination>
    )
}

export default PaginationList