import React, { useState } from 'react';
import {Row, Col, Card, Button} from 'react-bootstrap';
import { Link } from 'react-router-dom'


import Aux from "../../hoc/_Aux";

import "./Ocupacoes.css"

// Componentes
import SelectOcupation from '../../Components/SelectOcupation'
import Redirecionar from '../../Components/Redirecionar'


// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const searchByOcupation = (e, listaOcupacoes) => {
   
    const searchString = e.target.value
    let newList = []

    if(searchString === '')
        return false

    listaOcupacoes.filter((item) => {
        if(item.NM_OCUPACAO.toLowerCase().includes(searchString.toLowerCase())){

            newList.push(item)

            return true
        }

        return false
    })

    
    return newList
}

const itemsPerPage = 6

const Ocupacoes = (props) => {

    const listaOcupacoes = useSelector(state => state.listaOcupacoes)
    const cursoSelecionado = useSelector(state => state.cursoSelecionado)
    const ocupacoes = useSelector(state => state.ocupacoes)

    // Estado local
    const [pagesQty, setPagesQty] = useState(Math.ceil(listaOcupacoes.length / itemsPerPage))
    const [pagesQtyAdded, setPagesQtyAdded] = useState(Math.ceil(ocupacoes.length / itemsPerPage))

    let filtered = useSelector(state => state.listaOcupacoesFiltrado)
    const cardTitle = <Card.Title as="h5">Curso selecionado: <b>{cursoSelecionado.NO_CINE_ROTULO}</b>. Adicione, remova ou substitua ocupações relacionadas ao curso.</Card.Title>
    const pageTitle = `Selecionar ocupações` 

    const dispach = useDispatch()


    return (
        <Aux>
            <Redirecionar/>
            <Row>
                <Col>
                    <h2>{pageTitle}</h2>
                    <Card>
                        <Card.Header>
                            {cardTitle}
                        </Card.Header>
                        <Card.Body>
                            
                            <SelectOcupation
                                listaOcupacoes={listaOcupacoes}
                                ocupacoes={ocupacoes}
                                pagesQty={pagesQty}
                                setPagesQty={setPagesQty}
                                pagesQtyAdded={pagesQtyAdded}
                                setPagesQtyAdded={setPagesQtyAdded}
                                itemsPerPage={itemsPerPage}
                            />

                            <div className='btn-finalizar-ocupacoes'>
                                <Link to="/dashboard">
                                    <Button className='headerButton' variant={"danger"} onClick={() => {
                                        dispach({ type: 'DISCARD_OCUPATION' })
                                    }}>
                                        Descartar
                                    </Button>
                                </Link>
                                <Link to="/dashboard">
                                    <Button className='headerButton' variant={"primary"} onClick={() => {
                                        dispach({ type: 'SAVE_OCUPATION' })
                                    }}>
                                        Salvar
                                    </Button>
                                </Link>
                            </div>

                        </Card.Body>
                    </Card>
                </Col>
            </Row>
        </Aux>
    )
}


export default Ocupacoes;